1907         libcrun_fail_with_error (errno, "executable file not found in $PATH");
1908       libcrun_fail_with_error (errno, "exec");
1909       _exit (EXIT_FAILURE);
1910     }
1911 
1912   if (seccomp_fd >= 0)
1913     close_and_reset (&seccomp_fd);
1914 
1915   if (terminal_fd >= 0)
1916     {
1917       unsigned short rows = 0, cols = 0;
1918 
1919       if (process->console_size)
1920         {
1921           cols = process->console_size->width;
1922           rows = process->console_size->height;
1923         }
1924 
1925       ret = libcrun_terminal_setup_size (terminal_fd, rows, cols, err);
1926       if (UNLIKELY (ret < 0))
1927         return ret;
1928 
1929       if (context->console_socket)
1930         {
1931           int ret;
1932           cleanup_close int console_socket_fd = open_unix_domain_client_socket (context->console_socket, 0, err);
1933           if (UNLIKELY (console_socket_fd < 0))
1934             return console_socket_fd;
1935           ret = send_fd_to_socket (console_socket_fd, terminal_fd, err);
1936           if (UNLIKELY (ret < 0))
1937             return ret;
1938           close_and_reset (&terminal_fd);
1939         }
1940       else
1941         {
1942           ret = libcrun_setup_terminal_master (terminal_fd, &orig_terminal, err);
1943           if (UNLIKELY (ret < 0))
1944             {
1945               flush_fd_to_err (context, terminal_fd);
1946               return ret;
1947             }
1948         }
1949     }
1950 
1951   ret = wait_for_process (pid, context, terminal_fd, -1, -1, err);
1952 
1953   flush_fd_to_err (context, terminal_fd);
1954   return ret;
1955 }
