1970     return ret;
1971 
1972   ret = parse_json_file (&tree, content, &ctx, err);
1973   if (UNLIKELY (ret < 0))
1974     return ret;
1975 
1976   process = make_oci_container_process (tree, &ctx, &parser_err);
1977   if (UNLIKELY (process == NULL))
1978     {
